 1→import type { ParsedMessage } from "./claude-code";
 2→
 3→export type BlockCategory =
 4→  | "scaffold"
 5→  | "feature"
 6→  | "bug_fix"
 7→  | "refactor"
 8→  | "question"
 9→  | "file_change"
10→  | "command";
11→
12→const BUG_PATTERN = /\b(fix|bug|error|issue|broken|crash|fail|typo|patch)\b/i;
13→const REFACTOR_PATTERN = /\b(refactor|clean|reorganize|rename|simplify|extract)\b/i;
14→const WRITE_TOOLS = new Set(["Write", "Edit", "NotebookEdit"]);
15→
16→export function categorizeBlock(
17→  msg: ParsedMessage,
18→  index: number,
19→  total: number
20→): BlockCategory {
21→  // Tool-based categories take priority
22→  if (msg.toolAction) {
23→    if (WRITE_TOOLS.has(msg.toolAction)) return "file_change";
24→    if (msg.toolAction === "Bash") return "command";
25→  }
26→
27→  // Human questions
28→  if (msg.role === "human" && msg.content.includes("?")) return "question";
29→
30→  // Content-based heuristics
31→  if (BUG_PATTERN.test(msg.content)) return "bug_fix";
32→  if (REFACTOR_PATTERN.test(msg.content)) return "refactor";
33→
34→  // Early assistant messages are likely scaffolding
35→  if (index < 5 && msg.role === "assistant") return "scaffold";
36→
37→  return "feature";
38→}
39→
40→export function extractFilesTouched(msg: ParsedMessage): string[] {
41→  if (!msg.filePath) return [];
42→  // Normalize and dedupe
43→  return [msg.filePath.replace(/^\/+/, "")];
44→}
