 1→import { createBrowserClient } from "@supabase/ssr";
 2→import type { Database } from "@/types/database";
 3→
 4→let client: ReturnType<typeof createBrowserClient<Database>> | null = null;
 5→
 6→export function createClient() {
 7→  if (client) return client;
 8→
 9→  client = createBrowserClient<Database>(
10→    process.env.NEXT_PUBLIC_SUPABASE_URL!,
11→    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
12→  );
13→
14→  return client;
15→}
