  1→"use client";
  2→
  3→import {
  4→  createContext,
  5→  useContext,
  6→  useReducer,
  7→  type Dispatch,
  8→  type ReactNode,
  9→} from "react";
 10→import type { Difficulty, GuideType } from "@/types";
 11→import type { MediaFile } from "@/components/create/media-upload";
 12→
 13→// ─── Client-side types ───────────────────────────────────
 14→
 15→export interface ClientBlock {
 16→  clientId: string;
 17→  role: "human" | "assistant";
 18→  content: string;
 19→  toolAction: string | null;
 20→  filePath: string | null;
 21→  originalOrder: number;
 22→  autoCategory: string | null;
 23→  filesTouched: string[];
 24→  assignedToStepId: string | null;
 25→}
 26→
 27→export interface ClientStepBlock {
 28→  clientId: string;
 29→  blockClientId: string;
 30→  position: number;
 31→  displayMode: "full" | "collapsed" | "trimmed" | "ghost";
 32→  authorNote: string;
 33→}
 34→
 35→export interface ClientStep {
 36→  clientId: string;
 37→  title: string;
 38→  description: string;
 39→  authorAnnotation: string;
 40→  suggestedPrompt: string;
 41→  checkpointDescription: string;
 42→  order: number;
 43→  blockAssignments: ClientStepBlock[];
 44→}
 45→
 46→// ─── State ───────────────────────────────────────────────
 47→
 48→export interface GuideBuilderState {
 49→  // Metadata
 50→  title: string;
 51→  description: string;
 52→  difficulty: Difficulty | null;
 53→  timeEstimate: number | null;
 54→  isVibeCoded: boolean;
 55→  guideType: GuideType;
 56→  prerequisites: string[];
 57→  whatYoullBuild: string;
 58→  techs: string[];
 59→  categoryId: string | null;
 60→  mediaFiles: MediaFile[];
 61→
 62→  // Content
 63→  blocks: ClientBlock[];
 64→  steps: ClientStep[];
 65→
 66→  // UI
 67→  publishing: boolean;
 68→  error: string;
 69→  originalJson: string | null;
 70→}
 71→
 72→export const initialState: GuideBuilderState = {
 73→  title: "",
 74→  description: "",
 75→  difficulty: null,
 76→  timeEstimate: null,
 77→  isVibeCoded: false,
 78→  guideType: "full_app",
 79→  prerequisites: [],
 80→  whatYoullBuild: "",
 81→  techs: [],
 82→  categoryId: null,
 83→  mediaFiles: [],
 84→  blocks: [],
 85→  steps: [],
 86→  publishing: false,
 87→  error: "",
 88→  originalJson: null,
 89→};
 90→
 91→// ─── Actions ─────────────────────────────────────────────
 92→
 93→export type GuideBuilderAction =
 94→  | { type: "SET_TITLE"; payload: string }
 95→  | { type: "SET_DESCRIPTION"; payload: string }
 96→  | { type: "SET_DIFFICULTY"; payload: Difficulty | null }
 97→  | { type: "SET_TIME_ESTIMATE"; payload: number | null }
 98→  | { type: "SET_VIBE_CODED"; payload: boolean }
 99→  | { type: "SET_GUIDE_TYPE"; payload: GuideType }
100→  | { type: "SET_PREREQUISITES"; payload: string[] }
101→  | { type: "SET_WHAT_YOULL_BUILD"; payload: string }
102→  | { type: "SET_TECHS"; payload: string[] }
103→  | { type: "SET_CATEGORY_ID"; payload: string | null }
104→  | { type: "SET_MEDIA_FILES"; payload: MediaFile[] }
105→  | { type: "IMPORT_BLOCKS"; payload: { blocks: ClientBlock[]; originalJson: string } }
106→  | { type: "CLEAR_BLOCKS" }
107→  | { type: "ADD_STEP" }
108→  | { type: "REMOVE_STEP"; payload: string }
109→  | { type: "REORDER_STEPS"; payload: string[] }
110→  | { type: "UPDATE_STEP"; payload: { stepId: string; field: keyof Omit<ClientStep, "clientId" | "order" | "blockAssignments">; value: string } }
111→  | { type: "ASSIGN_BLOCK"; payload: { blockClientId: string; stepClientId: string } }
112→  | { type: "UNASSIGN_BLOCK"; payload: { blockClientId: string; stepClientId: string } }
113→  | { type: "REORDER_STEP_BLOCKS"; payload: { stepClientId: string; blockClientIds: string[] } }
114→  | { type: "SET_BLOCK_DISPLAY_MODE"; payload: { stepClientId: string; blockClientId: string; mode: ClientStepBlock["displayMode"] } }
115→  | { type: "SET_BLOCK_AUTHOR_NOTE"; payload: { stepClientId: string; blockClientId: string; note: string } }
116→  | { type: "SET_PUBLISHING"; payload: boolean }
117→  | { type: "SET_ERROR"; payload: string };
118→
119→// ─── ID helper ───────────────────────────────────────────
120→
121→let _counter = 0;
122→export function clientId(): string {
123→  return `c_${Date.now()}_${++_counter}`;
124→}
125→
126→// ─── Reducer ─────────────────────────────────────────────
127→
128→export function guideBuilderReducer(
129→  state: GuideBuilderState,
130→  action: GuideBuilderAction
131→): GuideBuilderState {
132→  switch (action.type) {
133→    case "SET_TITLE":
134→      return { ...state, title: action.payload };
135→    case "SET_DESCRIPTION":
136→      return { ...state, description: action.payload };
137→    case "SET_DIFFICULTY":
138→      return { ...state, difficulty: action.payload };
139→    case "SET_TIME_ESTIMATE":
140→      return { ...state, timeEstimate: action.payload };
141→    case "SET_VIBE_CODED":
142→      return { ...state, isVibeCoded: action.payload };
143→    case "SET_GUIDE_TYPE":
144→      return { ...state, guideType: action.payload };
145→    case "SET_PREREQUISITES":
146→      return { ...state, prerequisites: action.payload };
147→    case "SET_WHAT_YOULL_BUILD":
148→      return { ...state, whatYoullBuild: action.payload };
149→    case "SET_TECHS":
150→      return { ...state, techs: action.payload };
151→    case "SET_CATEGORY_ID":
152→      return { ...state, categoryId: action.payload };
153→    case "SET_MEDIA_FILES":
154→      return { ...state, mediaFiles: action.payload };
155→
156→    case "IMPORT_BLOCKS":
157→      return {
158→        ...state,
159→        blocks: action.payload.blocks,
160→        originalJson: action.payload.originalJson,
161→      };
162→
163→    case "CLEAR_BLOCKS":
164→      return {
165→        ...state,
166→        blocks: [],
167→        originalJson: null,
168→        steps: state.steps.map((s) => ({ ...s, blockAssignments: [] })),
169→      };
170→
171→    case "ADD_STEP": {
172→      const newStep: ClientStep = {
173→        clientId: clientId(),
174→        title: "",
175→        description: "",
176→        authorAnnotation: "",
177→        suggestedPrompt: "",
178→        checkpointDescription: "",
179→        order: state.steps.length,
180→        blockAssignments: [],
181→      };
182→      return { ...state, steps: [...state.steps, newStep] };
183→    }
184→
185→    case "REMOVE_STEP": {
186→      const removedStep = state.steps.find((s) => s.clientId === action.payload);
187→      const freedBlockIds = new Set(
188→        removedStep?.blockAssignments.map((a) => a.blockClientId) ?? []
189→      );
190→      return {
191→        ...state,
192→        steps: state.steps
193→          .filter((s) => s.clientId !== action.payload)
194→          .map((s, i) => ({ ...s, order: i })),
195→        blocks: state.blocks.map((b) =>
196→          freedBlockIds.has(b.clientId)
197→            ? { ...b, assignedToStepId: null }
198→            : b
199→        ),
200→      };
201→    }
202→
203→    case "REORDER_STEPS": {
204→      const orderMap = new Map(action.payload.map((id, i) => [id, i]));
205→      return {
206→        ...state,
207→        steps: [...state.steps]
208→          .sort((a, b) => (orderMap.get(a.clientId) ?? 0) - (orderMap.get(b.clientId) ?? 0))
209→          .map((s, i) => ({ ...s, order: i })),
210→      };
211→    }
212→
213→    case "UPDATE_STEP":
214→      return {
215→        ...state,
216→        steps: state.steps.map((s) =>
217→          s.clientId === action.payload.stepId
218→            ? { ...s, [action.payload.field]: action.payload.value }
219→            : s
220→        ),
221→      };
222→
223→    case "ASSIGN_BLOCK": {
224→      const { blockClientId, stepClientId } = action.payload;
225→      const targetStep = state.steps.find((s) => s.clientId === stepClientId);
226→      if (!targetStep) return state;
227→      const already = targetStep.blockAssignments.some(
228→        (a) => a.blockClientId === blockClientId
229→      );
230→      if (already) return state;
231→
232→      return {
233→        ...state,
234→        blocks: state.blocks.map((b) =>
235→          b.clientId === blockClientId
236→            ? { ...b, assignedToStepId: stepClientId }
237→            : b
238→        ),
239→        steps: state.steps.map((s) =>
240→          s.clientId === stepClientId
241→            ? {
242→                ...s,
243→                blockAssignments: [
244→                  ...s.blockAssignments,
245→                  {
246→                    clientId: clientId(),
247→                    blockClientId,
248→                    position: s.blockAssignments.length,
249→                    displayMode: "full" as const,
250→                    authorNote: "",
251→                  },
252→                ],
253→              }
254→            : s
255→        ),
256→      };
257→    }
258→
259→    case "UNASSIGN_BLOCK": {
260→      const { blockClientId, stepClientId } = action.payload;
261→      return {
262→        ...state,
263→        blocks: state.blocks.map((b) =>
264→          b.clientId === blockClientId
265→            ? { ...b, assignedToStepId: null }
266→            : b
267→        ),
268→        steps: state.steps.map((s) =>
269→          s.clientId === stepClientId
270→            ? {
271→                ...s,
272→                blockAssignments: s.blockAssignments
273→                  .filter((a) => a.blockClientId !== blockClientId)
274→                  .map((a, i) => ({ ...a, position: i })),
275→              }
276→            : s
277→        ),
278→      };
279→    }
280→
281→    case "REORDER_STEP_BLOCKS": {
282→      const { stepClientId, blockClientIds } = action.payload;
283→      return {
284→        ...state,
285→        steps: state.steps.map((s) => {
286→          if (s.clientId !== stepClientId) return s;
287→          const byBlockId = new Map(
288→            s.blockAssignments.map((a) => [a.blockClientId, a])
289→          );
290→          return {
291→            ...s,
292→            blockAssignments: blockClientIds
293→              .map((id, i) => {
294→                const existing = byBlockId.get(id);
295→                return existing ? { ...existing, position: i } : null;
296→              })
297→              .filter((a): a is ClientStepBlock => a !== null),
298→          };
299→        }),
300→      };
301→    }
302→
303→    case "SET_BLOCK_DISPLAY_MODE":
304→      return {
305→        ...state,
306→        steps: state.steps.map((s) =>
307→          s.clientId === action.payload.stepClientId
308→            ? {
309→                ...s,
310→                blockAssignments: s.blockAssignments.map((a) =>
311→                  a.blockClientId === action.payload.blockClientId
312→                    ? { ...a, displayMode: action.payload.mode }
313→                    : a
314→                ),
315→              }
316→            : s
317→        ),
318→      };
319→
320→    case "SET_BLOCK_AUTHOR_NOTE":
321→      return {
322→        ...state,
323→        steps: state.steps.map((s) =>
324→          s.clientId === action.payload.stepClientId
325→            ? {
326→                ...s,
327→                blockAssignments: s.blockAssignments.map((a) =>
328→                  a.blockClientId === action.payload.blockClientId
329→                    ? { ...a, authorNote: action.payload.note }
330→                    : a
331→                ),
332→              }
333→            : s
334→        ),
335→      };
336→
337→    case "SET_PUBLISHING":
338→      return { ...state, publishing: action.payload };
339→    case "SET_ERROR":
340→      return { ...state, error: action.payload };
341→
342→    default:
343→      return state;
344→  }
345→}
