 45→interface CreateGuideInput {
 46→  title: string;
 47→  description: string;
 48→  techs: string[];
 49→  categoryId: string | null;
 50→  mediaFiles: MediaFile[];
 51→  chatMessages: ParsedMessage[];
 52→}
 53→
 54→export async function createGuide(input: CreateGuideInput & { userId: string }): Promise<string | null> {
 55→  const supabase = createClient();
 56→  const userId = input.userId;
 57→
 58→  // 1. Insert post
 59→  const { data: post, error: postError } = await supabase
 60→    .from("posts")
 61→    .insert({
 62→      user_id: userId,
 63→      title: input.title,
 64→      description: input.description,
 65→      techs: input.techs,
 66→      category_id: input.categoryId,
 67→    })
 68→    .select("id")
 69→    .single();
 70→
 71→  if (postError || !post) {
 72→    console.error("Failed to create guide:", postError?.message);
 73→    return null;
 74→  }
 75→
 76→  // 2. Upload media files
 77→  if (input.mediaFiles.length > 0) {
 78→    const mediaRows = [];
 79→
 80→    for (let i = 0; i < input.mediaFiles.length; i++) {
 81→      const media = input.mediaFiles[i];
 82→      const ext = media.file.name.split(".").pop();
 83→      const path = `${userId}/${post.id}/${i}.${ext}`;
 84→
 85→      const { error: uploadError } = await supabase.storage
 86→        .from("post-media")
 87→        .upload(path, media.file);
 88→
 89→      if (uploadError) {
 90→        console.error("Upload error:", uploadError.message);
 91→        continue;
 92→      }
 93→
 94→      const { data: urlData } = supabase.storage
 95→        .from("post-media")
 96→        .getPublicUrl(path);
 97→
 98→      mediaRows.push({
 99→        post_id: post.id,
100→        url: urlData.publicUrl,
101→        type: media.type,
102→        order: i,
103→      });
104→    }
105→
106→    if (mediaRows.length > 0) {
107→      await supabase.from("post_media").insert(mediaRows);
108→    }
109→  }
110→
111→  // 3. Save chat messages
112→  if (input.chatMessages.length > 0) {
113→    const chatRows = input.chatMessages.map((msg, i) => ({
114→      post_id: post.id,
115→      role: msg.role,
116→      content: msg.content,
117→      tool_action: msg.toolAction,
118→      file_path: msg.filePath,
119→      order: i,
120→    }));
121→
122→    // Insert in batches of 500 (Supabase limit)
123→    for (let i = 0; i < chatRows.length; i += 500) {
124→      const batch = chatRows.slice(i, i + 500);
125→      const { error: chatError } = await supabase
126→        .from("chat_messages")
127→        .insert(batch);
128→
129→      if (chatError) {
130→        console.error("Chat insert error:", chatError.message);
131→      }
132→    }
133→  }
134→
135→  return post.id;
136→}
