 8→export function formatNumber(num: number | null | undefined): string {
 9→  const n = num ?? 0;
10→  if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
11→  if (n >= 1_000) return `${(n / 1_000).toFixed(1)}K`;
12→  return n.toString();
13→}
