15→export function formatRelativeTime(dateString: string): string {
16→  const date = new Date(dateString);
17→  const now = new Date();
18→  const diffMs = now.getTime() - date.getTime();
19→  const diffSec = Math.floor(diffMs / 1000);
20→  const diffMin = Math.floor(diffSec / 60);
21→  const diffHour = Math.floor(diffMin / 60);
22→  const diffDay = Math.floor(diffHour / 24);
23→  const diffWeek = Math.floor(diffDay / 7);
24→  const diffMonth = Math.floor(diffDay / 30);
25→  const diffYear = Math.floor(diffDay / 365);
26→
27→  if (diffSec < 60) return "just now";
28→  if (diffMin < 60) return `${diffMin}m ago`;
29→  if (diffHour < 24) return `${diffHour}h ago`;
30→  if (diffDay < 7) return `${diffDay}d ago`;
31→  if (diffWeek < 5) return `${diffWeek}w ago`;
32→  if (diffMonth < 12) return `${diffMonth}mo ago`;
33→  return `${diffYear}y ago`;
34→}
