36→export function slugify(text: string): string {
37→  return text
38→    .toLowerCase()
39→    .trim()
40→    .replace(/[^\w\s-]/g, "")
41→    .replace(/[\s_]+/g, "-")
42→    .replace(/-+/g, "-")
43→    .replace(/^-+|-+$/g, "")
44→    || "untitled";
45→}
