#### 4d. Decision API Route (`src/app/api/oauth/decision/route.ts`)

```typescript
// src/app/api/oauth/decision/route.ts
import { NextRequest, NextResponse } from "next/server";
import { createClient } from "@/lib/supabase/server";

export async function POST(request: NextRequest) {
  const formData = await request.formData();
  const decision = formData.get("decision") as string;
  const authorizationId = formData.get("authorization_id") as string;

  if (!authorizationId) {
    return NextResponse.json({ error: "Missing authorization_id" }, { status: 400 });
  }

  const supabase = await createClient();

  if (decision === "approve") {
    const { data, error } = await supabase.auth.oauth.approveAuthorization(authorizationId);
    if (error) {
      return NextResponse.json({ error: error.message }, { status: 400 });
    }
    return NextResponse.redirect(data.redirect_to);
  } else {
    const { data, error } = await supabase.auth.oauth.denyAuthorization(authorizationId);
    if (error) {
      return NextResponse.json({ error: error.message }, { status: 400 });
    }
    return NextResponse.redirect(data.redirect_to);
  }
}
```

#### 4e. Token Resolution Helper (`src/lib/mcp/auth.ts`)

This utility takes a Bearer token from MCP requests and resolves it to a user ID using Supabase.

```typescript
// src/lib/mcp/auth.ts
import { createClient as createAdminClient } from "@supabase/supabase-js";

// Use the service role key to verify tokens server-side
const supabaseAdmin = createAdminClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_ROLE_KEY!
);

export async function resolveUserFromBearer(token: string): Promise<string | null> {
  const { data: { user }, error } = await supabaseAdmin.auth.getUser(token);
  if (error || !user) return null;
  return user.id;
}
```

This uses the Supabase Admin client with the service role key so that `getUser(token)` validates the JWT and returns the user. The admin client is necessary because the token comes from an external MCP client, not from a browser cookie.

**Environment variable needed**: `SUPABASE_SERVICE_ROLE_KEY` must be set in `.env.local`.

### 5. MCP Tool Implementations

#### 5a. `create_guide` Tool (`src/lib/mcp/tools/create-guide.ts`)

This is the most complex tool. It reuses the existing `parseClaudeCodeJsonl()` parser and `categorizeBlock()` + `extractFilesTouched()` functions, then performs database inserts similar to `publishGuide()` from `src/lib/supabase/queries/create-guide.ts`.

**Key difference from the web UI flow**: The MCP tool does not produce steps or step_blocks. It only creates the post, guide_blocks, and chat_messages. This is because MCP clients send raw JSONL without any user-organized step structure. The guide can be edited later in the web UI to add steps.

```typescript
// src/lib/mcp/tools/create-guide.ts
import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { z } from "zod";
import { parseClaudeCodeJsonl } from "@/lib/parser/claude-code";
import { categorizeBlock, extractFilesTouched } from "@/lib/parser/categorize-block";
import { createClient as createAdminClient } from "@supabase/supabase-js";
import { slugify } from "@/lib/utils";

const supabaseAdmin = createAdminClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_ROLE_KEY!
);

export function registerCreateGuideTool(server: McpServer, userId: string) {
  server.registerTool(
    "create_guide",
    {
      title: "Create Guide",
      description:
        "Parse a Claude Code JSONL conversation export and create a guide on Pathway. " +
        "Returns the URL of the created guide.",
      inputSchema: z.object({
        jsonl_content: z.string().describe("The raw JSONL content from a Claude Code conversation export"),
        title: z.string().min(1).max(200).describe("Guide title"),
        description: z.string().min(1).max(2000).describe("Short description of what this guide covers"),
        difficulty: z.enum(["beginner", "intermediate", "advanced"]).optional()
          .describe("Difficulty level"),
        guide_type: z.enum([
          "full_app", "component", "integration", "automation",
          "game", "cli_tool", "chrome_extension", "other"
        ]).optional().describe("Type of guide"),
        category_id: z.string().uuid().optional()
          .describe("Category UUID. Use list_categories to get available IDs."),
        techs: z.array(z.string()).optional()
          .describe("Technology tags, e.g. ['Next.js', 'TypeScript', 'Supabase']"),
        publish: z.boolean().optional().default(false)
          .describe("If true, guide is immediately visible. Defaults to false (draft/hidden)."),
      }),
    },
    async ({ jsonl_content, title, description, difficulty, guide_type, category_id, techs, publish }) => {
      // 1. Parse the JSONL content
      const messages = parseClaudeCodeJsonl(jsonl_content);
      if (messages.length === 0) {
        return {
          content: [{ type: "text", text: "Error: No valid messages found in the JSONL content." }],
          isError: true,
        };
      }

      // 2. Insert the post
      const { data: post, error: postError } = await supabaseAdmin
        .from("posts")
        .insert({
          user_id: userId,
          title: title.trim(),
          description: description.trim(),
          difficulty: difficulty ?? null,
          guide_type: guide_type ?? "other",
          category_id: category_id ?? null,
          techs: techs ?? [],
          is_hidden: !publish,     // draft = hidden
          original_json: jsonl_content,
        })
        .select("id")
        .single();

      if (postError || !post) {
        return {
          content: [{ type: "text", text: `Error creating guide: ${postError?.message}` }],
          isError: true,
        };
      }

      const postId = post.id;

      // 3. Build and insert guide_blocks
      const blockRows = messages.map((msg, i) => ({
        post_id: postId,
        role: msg.role,
        content: msg.content,
        tool_action: msg.toolAction,
        file_path: msg.filePath,
        original_order: i,
        auto_category: categorizeBlock(msg, i, messages.length),
        files_touched: extractFilesTouched(msg),
      }));

      // Insert in batches of 500
      for (let i = 0; i < blockRows.length; i += 500) {
        const batch = blockRows.slice(i, i + 500);
        const { error: blockError } = await supabaseAdmin
          .from("guide_blocks")
          .insert(batch);

        if (blockError) {
          console.error("guide_blocks insert error:", blockError.message);
        }
      }

      // 4. Insert chat_messages (backward compat for timeline view)
      const chatRows = messages.map((msg, i) => ({
        post_id: postId,
        role: msg.role,
        content: msg.content,
        tool_action: msg.toolAction,
        file_path: msg.filePath,
        order: i,
      }));

      for (let i = 0; i < chatRows.length; i += 500) {
        const batch = chatRows.slice(i, i + 500);
        const { error: chatError } = await supabaseAdmin
          .from("chat_messages")
          .insert(batch);

        if (chatError) {
          console.error("chat_messages insert error:", chatError.message);
        }
      }

      // 5. Construct the guide URL
      const baseUrl = process.env.NEXT_PUBLIC_APP_URL || "https://pathway.app";
      const guideUrl = `${baseUrl}/guide/${postId}/${slugify(title)}`;

      const statusText = publish ? "published" : "saved as draft";

      return {
        content: [{
          type: "text",
          text: [
            `Guide ${statusText} successfully!`,
            `Title: ${title}`,
            `Messages parsed: ${messages.length}`,
            `Blocks created: ${blockRows.length}`,
            `URL: ${guideUrl}`,
            publish ? "" : "The guide is hidden (draft). Edit it on the web to add steps and publish.",
          ].filter(Boolean).join("\n"),
        }],
      };
    }
  );
}
```

**Why use the admin client here instead of a user-scoped client?** The admin client with the service role key bypasses RLS. This is necessary because we authenticated the user via Bearer token (not via Supabase cookie session), so we cannot construct a standard Supabase server client with the user's session. The `user_id` is set explicitly in the INSERT, and since we verified the token in the auth middleware, this is safe. An alternative approach would be to create a Supabase client with the user's access token using `createClient` with custom auth header, which would respect RLS. This is the preferred approach for production, and the implementation should do this:

```typescript
import { createClient } from "@supabase/supabase-js";

function createUserClient(accessToken: string) {
  return createClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      global: {
        headers: {
          Authorization: `Bearer ${accessToken}`,
        },
      },
    }
  );
}
```

This approach is better because it leverages existing RLS policies (e.g., `guide_blocks_insert` checks `EXISTS (SELECT 1 FROM posts WHERE id = post_id AND user_id = auth.uid())`). I recommend this approach. The `userId` parameter would then come from the token validation, and the Supabase client with the user's access token would be passed into the tool registration for all queries.

